import React from 'react';
import WeeklyCalendar from './WeeklyCalendar';
import StreakDisplay from './StreakDisplay';

function HabitItem({ habit, onToggle }) {
  const today = new Date().toISOString().split('T')[0];

  const toggleToday = (intensity) => {
    onToggle(habit.id, today, intensity);
  };

  const calculateStreak = () => {
    const completions = habit.completions;
    let streak = 0;
    let date = new Date(today);
    while (true) {
      const dateStr = date.toISOString().split('T')[0];
      if (completions[dateStr] > 0) {
        streak++;
        date.setDate(date.getDate() - 1);
      } else {
        break;
      }
    }
    return streak;
  };

  const streak = calculateStreak();

  const badges = [];
  if (streak >= 7) badges.push('7-day');
  if (streak >= 30) badges.push('30-day');
  if (streak >= 100) badges.push('100-day');

  return (
    <div className="bg-white p-4 rounded shadow mb-4">
      <div className="flex justify-between items-center mb-2">
        <h2 className="text-xl font-semibold">{habit.name}</h2>
        <div className="flex items-center">
          <StreakDisplay streak={streak} />
          {badges.map(badge => (
            <span key={badge} className="ml-2 bg-yellow-500 text-white px-2 py-1 rounded text-xs">
              {badge}
            </span>
          ))}
        </div>
      </div>
      <div className="flex items-center mb-4">
        {[1,2,3,4,5].map(level => (
          <button
            key={level}
            onClick={() => toggleToday(level)}
            className={`px-2 py-1 mx-1 rounded ${habit.completions[today] === level ? 'bg-green-500 text-white' : 'bg-gray-300'}`}
          >
            {level}
          </button>
        ))}
        <button
          onClick={() => toggleToday(0)}
          className={`px-4 py-1 mx-1 rounded ${habit.completions[today] === 0 || !habit.completions[today] ? 'bg-red-500 text-white' : 'bg-gray-300'}`}
        >
          Skip
        </button>
      </div>
      <WeeklyCalendar habit={habit} />
    </div>
  );
}

export default HabitItem;
